var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"함선 밖의 대원들에게 알립니다! 서둘러 철수하십시오!","JPN":"艦船外の隊員にお知らせします！　速やかに撤収してください！","ENG":"Attention, all members off-ship! Evacuate immediately!","TWN":"通知艦船外面的隊員們！趕快撤退！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"엔터프라이즈 쿼드의 화력만으로는 강습하는 침식체들을 전부 요격할 수 없습니다!","JPN":"エンタープライズクワッドの火力だけでは襲ってくる侵食体をすべて迎撃することはできません！","ENG":"The Enterprise Quad does not have enough firepower to fire at all the attacking C.O.s!","TWN":"僅憑企業4號的火力，沒辦法攔截襲擊而來的全部侵蝕體！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"괜찮아요! 그래 봐야 과녁만 늘어날 뿐이니까!","JPN":"大丈夫ですよ！　どうせ狙う的が増えるだけですから！","ENG":"It's okay! It just means more targets for me!","TWN":"沒關係！因為那樣只是增加槍下魂而已！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"여, 역시 중화기의 정령님……! 믿음직스러워요……!","JPN":"さ、さすが重火器の精霊……！　頼もしいです……！","ENG":"M-Miss Big Guns...! You're so reliable...!","TWN":"不，不愧是重型武器精靈……！果然很可靠……！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"히, 힘내라, 힘!","JPN":"がーんばれ、がーんばれ！","ENG":"G-go get 'em!","TWN":"加，加油，加油！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"저 녀석들 소빈이는 왜 부추기는 거야?! 저러다 다치기라도 하면 어쩌려고!","JPN":"あいつら、コハルをなんで焚きつけんだ！？　怪我でもしたらどうするんだよ！","ENG":"Why are they encouraging Sobin?! What if she gets hurt?!","TWN":"那些傢伙為什麼慫恿起素蘋來了？！這樣下去她受傷怎麼辦！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"내버려 둬. 지금은 저렇게라도 안 하면 화력이 부족해.","JPN":"放っておいて。今はああでもしなければ火力が足りないわよ。","ENG":"Leave them be. We can use the firepower.","TWN":"別管了。現在不那麼做的話火力不夠。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"해적! 그쪽으로 몰려간다!","JPN":"海賊！　そっちに大量に行くぞ！","ENG":"Pirate! They're heading over to you!","TWN":"海盜！退到那邊！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"올레. 역시 저격수답게 시야가 넓군.","JPN":"オーレ。さすがはスナイパー、視野が広いな。","ENG":"Olé. Good eyes, like a true sniper.","TWN":"好的。不愧是狙擊手，視野就是開闊。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"이 녀석들, 생긴 건 비리비리하면서 손맛은 나쁘지 않아. 마음에 들어.","JPN":"こいつら、見た目はいかにも弱そうなのに、まぁまぁ手ごたえはある。気に入った。","ENG":"They look skinny and weak, but they're surprisingly fun to beat up. Not bad.","TWN":"這些傢伙，長得弱不禁風的樣子，本事還不錯。我喜歡。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"마음에 들면 아예 여기서 살림 차릴래? 작별 선물로 팔다리 한 짝씩만 떼어 주라.","JPN":"そんなに気に入っているならここに定着するか？　餞別として足と腕を一本ずつくれ。","ENG":"If you like it so much, you should stay here. Give me one arm and one leg, as a parting gift.","TWN":"喜歡的話你乾脆在這裡過日子啊？作為分別的禮物，給我留條胳膊和腿吧？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"이, 이 녀석들! 끝도 없이 몰려와! 눈앞이 온통 침식체뿐이야!","JPN":"こ、こいつら！　いくら倒してもキリがないぜ！　目の前が侵食体だらけだ！","ENG":"Th-these pests! They're endless! We're surrounded by C.O.s, everywhere in eyesight!","TWN":"這，這些傢伙！沒完沒了啊！現在到處都是侵蝕體！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L21_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"얼른 방패 뒤로 와! 앞에서 잘못 까불다간 진짜 죽는다고!","JPN":"早く盾の後ろに隠れろ！　変に前に出たら本当に死ぬぞ！","ENG":"Stand behind the shield! You're going to get yourself killed, running around the frontlines like that!","TWN":"快點躲到盾牌後面來！再在前面亂晃真的會死的！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"대령님! 수가 너무 많습니다!","JPN":"大佐！　敵が多すぎます！","ENG":"Colonel! There are too many of them!","TWN":"上校！數量太多了！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"홍수가 따로 없군. 이러다 우리 모두 저 녀석들에게 쓸려 나가겠어.","JPN":"まるで洪水のようだな。このままでは俺たち全員が押し流されてしまう。","ENG":"They're practically a flood. We're all going to get swept up unless we do something.","TWN":"簡直像洪水氾濫一樣。再這樣下去，會被直接淹沒的！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"메이슨 씨, 등대를 멈추려면 아직 멀었나?","JPN":"メイソンさん、灯台はまだ止められないか？","ENG":"Mr. Mason, how long till you can stop the Lighthouse?","TWN":"梅森，關掉燈塔需要很久嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L29_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그게 쉬우면 바로 했어!","JPN":"そう簡単にできるならとっくにやってる！","ENG":"It'd be done if it were that easy!","TWN":"要是容易我早就那麼做了！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"조금만 버텨! 임시로 복구한 거라 지금 잘못 건드렸다간 더는 손쓸 수 없게 돼!","JPN":"少しだけ耐えて！　やっと使えるぐらいまで復旧しただけだから、今下手に触ったらもう直せなくなるわ！","ENG":"Hold out just a bit longer! It's only a temporary fix, so we're going to break it for good if we're not careful!","TWN":"再堅持一下！因為是臨時恢復的，一個弄不好就再也修不了！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"엔지니어 분들께서 그렇다니까 우리가 어떻게든 분발해야겠어.","JPN":"エンジニアのみなさんがそうおっしゃるなら、俺たちでなんとか頑張らないとな。","ENG":"If the engineers say so. We have to keep trying.","TWN":"工程師都這麼說了，那就沒辦法了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"준비됐나, 제이나?","JPN":"準備はいいか、ジェイナ？","ENG":"Are you ready, Jaina?","TWN":"準備好了嗎，婕娜？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"……네!","JPN":"……はい！","ENG":"...Yes!","TWN":"……是！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};